#include<bits/stdc++.h>using namespace std;int t,n,ans=0;struct node{	int x,id;}a[110];struct Node{	int l,r;}b[10010];bool check(node a[]){	for(int i=2;i<=n;i++){		if(a[i].x!=a[i-1].x) return false;	}	return true;}bool cmp(node n1,node n2){	return n1.x>n2.x;}int main(){	cin>>t;	while(t--){		cin>>n;		for(int i=1;i<=n;i++){			cin>>a[i].x;			a[i].id=i;		}		sort(a+1,a+n+1,cmp);		if(check(a)){			cout<<0<<endl;			continue;		}else{			if(a[n].x==1){				cout<<-1<<endl;				continue;			}else{				while(!check(a)){					for(int i=1,j=2;j<=n;j++){						if(a[i].x>a[j].x){							ans++;							a[i].x=ceil(a[i].x*1.0/a[j].x);							b[ans].l=a[i].id;							b[ans].r=a[j].id;							break;						}					}					sort(a+1,a+n+1,cmp);				}				cout<<ans<<endl;				for(int i=1;i<=ans;i++) cout<<b[i].l<<' '<<b[i].r<<endl;				ans=0;			}		}	}	return 0;}